import { useTranslation } from 'react-i18next'
import './LanguageSwitcher.css'

const LanguageSwitcher = () => {
    const { i18n } = useTranslation()

    const changeLanguage = (lng) => {
        i18n.changeLanguage(lng)
    }

    return (
        <div className="language-switcher">
            <p className="language-title">other language versions</p>
            <div className="flags">
                <button onClick={() => changeLanguage('en')} aria-label="English">
                    <img src="/flags/flag.uk.png" alt="English" />
                </button>
                <button onClick={() => changeLanguage('uk')} aria-label="Українська">
                    <img src="/flags/ua.png" alt="Українська" />
                </button>
            </div>
        </div>
    )
}

export default LanguageSwitcher
